sql:
SELECT COUNT(*) AS average_data_points 
FROM data 
WHERE survey_id = 0;

external_knowledge:
; 'intrepid explorers' is a metaphor for 'users';
; 'adventures starting with the 'S' trail' refers to surveys whose names begin with 'S';
; 'complexity of the variables they're facing' is a figurative way to describe the descending order of variable names;
; 'alphabetical admiration of their names' is a metaphorical expression for sorting in ascending order by user name.

- 'Explorers' refers to users with the role named 'researcher';
- 'dipped their toes' metaphorically means to view or interact with surveys;
- 'sailing the seas of view' metaphorically represents the act of viewing;
- 'forging the lands of modification' metaphorically represents the act of modifying.

sql:
SELECT surveys.survey_id, surveys.survey_name, variables.variable_name
FROM surveys
JOIN variables ON surveys.survey_id = variables.survey_id;

SELECT survey_name, description
FROM surveys
WHERE survey_id > 5 AND sponsor = 'Acme Inc.';

SELECT * 
FROM surveys 
WHERE survey_id IN (SELECT survey_id FROM data WHERE value = 'Value 2');

